uniform vec2 u_resolution;
uniform float u_time;
uniform sampler2D u_texture0;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;

    vec2 distortedUV = uv;
    distortedUV.x += 0.05 * sin(uv.y * 10.0 + u_time * 2.0);
    distortedUV.y += 0.05 * cos(uv.x * 10.0 + u_time * 2.0);

    fragColor = texture(u_texture0, distortedUV);
}

